#!/usr/bin/env python3
"""Generate registry views from the unified local Agent definitions."""

from __future__ import annotations

import argparse
import json
import re
import sys
from pathlib import Path
from typing import Any

WORKSPACE_ROOT = Path(__file__).resolve().parents[2]
AGENT_FRAMEWORK_ROOT = WORKSPACE_ROOT / "agent_framework"
CATALOG_DIR = AGENT_FRAMEWORK_ROOT / "catalog"
sys.path.insert(0, str(AGENT_FRAMEWORK_ROOT / "src"))

from research_runtime.definitions import (  # noqa: E402
    AGENT_DEFINITIONS,
    serialize_agent_definition,
)


def relative(path: Path) -> str:
    return path.relative_to(WORKSPACE_ROOT).as_posix()


def frontmatter(path: Path) -> dict[str, str]:
    text = path.read_text(encoding="utf-8", errors="replace")
    if not text.startswith("---\n"):
        return {}
    _, raw, _ = text.split("---", 2)
    values: dict[str, str] = {}
    for line in raw.splitlines():
        match = re.match(r"^([A-Za-z_][\w-]*):\s*(.*)$", line)
        if match:
            values[match.group(1)] = match.group(2).strip().strip("\"'")
    return values


def entry(
    identifier: str,
    source: str,
    title: str,
    path: Path,
    *,
    status: str,
    notes: str,
) -> dict[str, Any]:
    return {
        "id": identifier,
        "source": source,
        "title": title,
        "kind": "skill_descriptor",
        "status": status,
        "source_path": relative(path),
        "prerequisites": [],
        "notes": notes,
    }


def skill_status(path: Path) -> str:
    source_path = relative(path)
    if "/ai-trader/skills/" in source_path:
        return "requires_external_service_review"
    if "/ghostfolio/.agents/skills/" in source_path:
        return "guidance_descriptor_available"
    return "requires_source_runtime"


def collect_skills() -> list[dict[str, Any]]:
    roots = (
        ("AI-Trader", WORKSPACE_ROOT / "references" / "projects" / "ai-trader" / "skills"),
        (
            "Ghostfolio",
            WORKSPACE_ROOT / "references" / "projects" / "ghostfolio" / ".agents" / "skills",
        ),
        ("QuantSkills", WORKSPACE_ROOT / "references" / "projects" / "quantskills-agents"),
    )
    skills = []
    for source, root in roots:
        for path in sorted(root.rglob("SKILL.md")):
            metadata = frontmatter(path)
            skills.append(
                entry(
                    relative(path.parent).replace("/", ":"),
                    source,
                    metadata.get("name", path.parent.name),
                    path,
                    status=skill_status(path),
                    notes=metadata.get("description", ""),
                )
            )
    return skills


def serialize_agents() -> list[dict[str, Any]]:
    return [serialize_agent_definition(definition) for definition in AGENT_DEFINITIONS]


def validate_paths(skills: list[dict[str, Any]]) -> None:
    missing = []
    for definition in AGENT_DEFINITIONS:
        for path in (definition.source_path, definition.upstream_path):
            if not (WORKSPACE_ROOT / path).exists():
                missing.append(f"{definition.agent_id}:{path}")
    for skill in skills:
        if not (WORKSPACE_ROOT / skill["source_path"]).is_file():
            missing.append(f"{skill['id']}:{skill['source_path']}")
    if missing:
        raise RuntimeError(f"catalog references missing sources: {', '.join(missing)}")


def render_agent_table() -> str:
    lines = [
        "# 统一 Agent 表",
        "",
        "Generated by `scripts/build_agent_catalog.py`; do not edit manually.",
        "",
        "| ID | 来源 | 适配器 | 最低执行配置 | 任务类型 | 资源 | 本地定义 | 上游依据 |",
        "| --- | --- | --- | --- | --- | --- | --- | --- |",
    ]
    for definition in AGENT_DEFINITIONS:
        tasks = ", ".join(sorted(definition.task_types))
        resources = ", ".join(sorted(definition.required_resources)) or "—"
        lines.append(
            f"| `{definition.agent_id}` | {definition.source} | {definition.adapter.value} | "
            f"{definition.minimum_profile.value} | {tasks} | {resources} | "
            f"`{definition.source_path}` | `{definition.upstream_path}` |"
        )
    return "\n".join(lines) + "\n"


def render_skill_table(skills: list[dict[str, Any]]) -> str:
    lines = [
        "# Skill 表",
        "",
        "Generated by `scripts/build_agent_catalog.py`; do not edit manually.",
        "",
        "| ID | 来源 | 状态 | 源文件 |",
        "| --- | --- | --- | --- |",
    ]
    for item in skills:
        lines.append(
            f"| `{item['id']}` | {item['source']} | {item['status']} | "
            f"`{item['source_path']}` |"
        )
    return "\n".join(lines) + "\n"


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--check", action="store_true")
    arguments = parser.parse_args()
    skills = collect_skills()
    validate_paths(skills)
    if arguments.check:
        print(f"agents={len(AGENT_DEFINITIONS)} skills={len(skills)} paths=valid")
        return 0

    CATALOG_DIR.mkdir(parents=True, exist_ok=True)
    (CATALOG_DIR / "agents.json").write_text(
        json.dumps(serialize_agents(), ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )
    (CATALOG_DIR / "skills.json").write_text(
        json.dumps(skills, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )
    (CATALOG_DIR / "agent-table.md").write_text(
        render_agent_table(),
        encoding="utf-8",
    )
    (CATALOG_DIR / "skill-table.md").write_text(
        render_skill_table(skills),
        encoding="utf-8",
    )
    print(f"agents={len(AGENT_DEFINITIONS)} skills={len(skills)} written=agent_framework/catalog")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
